Move `useCallback` outside the conditional:

```jsx
// ❌ Wrong
function Component({ show }) {
if (show) {
const [state, setState] = useState(0); // Violation!
}
}

// ✅ Correct
function Component({ show }) {
const [state, setState] = useState(0);
if (!show) return null;
// Use state here...
}
```

Move `useCallback` to component level or use a custom hook:

```jsx
// ❌ Wrong
function Component() {
const handleClick = () => {
const [state] = useCallback(); // Violation!
};
}

// ✅ Correct
function Component() {
const [state, setState] = useCallback();
const handleClick = () => {
// Use state/setState here
};
}
```

